# agent.py — instrument the agent with the recorder
from recorder import TraceRecorder

def web_search(query: str) -> str:
    return f"[search results for: {query}]"

TOOL_FNS = {"web_search": web_search}
TOOLS_SCHEMA = [
    {"name": "web_search", "description": "Search the web",
     "input_schema": {"type": "object", "properties": {"query": {"type": "string"}}, "required": ["query"]}}
]

def run_agent_recorded(user_message: str, recorder: TraceRecorder) -> str:
    messages = [{"role": "user", "content": user_message}]
    while True:
        response = recorder.call_llm(
            messages=messages,
            model="claude-haiku-4-5-20251001",
            max_tokens=1024,
            tools=TOOLS_SCHEMA,
        )
        if response.stop_reason == "end_turn":
            return next(b.text for b in response.content if hasattr(b, "text"))
        messages.append({"role": "assistant", "content": response.content})
        results = []
        for block in response.content:
            if block.type == "tool_use":
                result = recorder.call_tool(
                    TOOL_FNS[block.name], block.name, **block.input
                )
                results.append({"type": "tool_result", "tool_use_id": block.id, "content": result})
        messages.append({"role": "user", "content": results})

if __name__ == "__main__":
    rec = TraceRecorder()
    answer = run_agent_recorded("What is OpenTelemetry?", rec)
    print(answer)
    rec.save("traces/run-001.json")
